class Router {
    constructor(memoryLimit) {
        this.limit = memoryLimit;
        this.packets = [];
        this.seen = new Set();
        this.byDest = new Map();
        this.destStart = new Map();
    }
    _key(s, d, t) {
        return s + ',' + d + ',' + t;
    }
    addPacket(source, destination, timestamp) {
        const key = this._key(source, destination, timestamp);
        if (this.seen.has(key)) return false;
        if (this.packets.length === this.limit) this._evict();
        this.packets.push([source, destination, timestamp, key]);
        this.seen.add(key);
        if (!this.byDest.has(destination)) {
            this.byDest.set(destination, []);
            this.destStart.set(destination, 0);
        }
        this.byDest.get(destination).push(timestamp);
        return true;
    }
    _evict() {
        const [, d, , key] = this.packets.shift();
        this.seen.delete(key);
        this.destStart.set(d, this.destStart.get(d) + 1);
    }
    forwardPacket() {
        if (this.packets.length === 0) return [];
        const [s, d, t, key] = this.packets.shift();
        this.seen.delete(key);
        this.destStart.set(d, this.destStart.get(d) + 1);
        return [s, d, t];
    }
    getCount(destination, startTime, endTime) {
        const arr = this.byDest.get(destination);
        if (!arr) return 0;
        const start = this.destStart.get(destination) || 0;
        const lo = this._lowerBound(arr, start, arr.length, startTime);
        const hi = this._upperBound(arr, start, arr.length, endTime);
        return Math.max(0, hi - lo);
    }
    _lowerBound(arr, lo, hi, target) {
        while (lo < hi) {
            const mid = (lo + hi) >> 1;
            if (arr[mid] < target) lo = mid + 1;
            else hi = mid;
        }
        return lo;
    }
    _upperBound(arr, lo, hi, target) {
        while (lo < hi) {
            const mid = (lo + hi) >> 1;
            if (arr[mid] <= target) lo = mid + 1;
            else hi = mid;
        }
        return hi;
    }
}
